const base64Audio = $input.first().json.base64;
if (!base64Audio) {
  throw new Error('Evolution API no devolvió base64 del audio');
}
const extraer = $('Extraer Datos del Mensaje').item.json;
return [{
  json: {
    sender_phone: extraer.sender_phone,
    message_id: extraer.message_id,
    instance_name: extraer.instance_name,
    message_type: extraer.message_type
  },
  binary: {
    audio: {
      data: base64Audio,
      mimeType: 'audio/ogg',
      fileName: 'audio.ogg',
      fileExtension: 'ogg'
    }
  }
}];
